	WHEN NO_DATA_FOUND THEN
		DBMS_OUTPUT.PUT_LINE('Departamento no existe');

CURSOR c_empleados IS
	SELECT e.NUMEM, e.NOMEM, e.SALAR
	FROM EMPLEADOS e
	WHERE e.NUMHI > 2 AND e.SALAR < 2000;
	v_salariofinal NUMBER;

CREATE OR REPLACE FUNCTION SALARIOS(DEP NUMBER)
RETURN NUMBER
IS
	V_SUM NUMBER := 0;
	CURSOR EMPLEADOS IS
	SELECT SAL FROM EMP
	WHERE DEPTNO = DEP;
BEGIN
	FOR EMPLEADO IN EMPLEADOS
	LOOP
		V_SUM := V_SUM + EMPLEADO;
	END LOOP;

	DBMS_OUTPUT.PUT_LINE(V_SUM);
END;

SELECT SALARIOS(10) FROM DUAL;

CREATE OR REPLACE PACKAGE BODY ARITMETICA AS

    PROCEDURE sumar(
        n1 NUMBER,
        n2 NUMBER
    )
    IS
    BEGIN
        DBMS_OUTPUT.PUT_LINE('Suma = ' || (n1 + n2));
    END sumar;


    PROCEDURE restar(
        n1 NUMBER,
        n2 NUMBER
    )
    IS
    BEGIN
        DBMS_OUTPUT.PUT_LINE('Resta = ' || (n1 - n2));
    END restar;


    FUNCTION multiplicar(
        n1 NUMBER,
        n2 NUMBER
    ) RETURN NUMBER
    IS
    BEGIN
        RETURN n1 * n2;
    END multiplicar;


    FUNCTION dividir(
        n1 NUMBER,
        n2 NUMBER
    ) RETURN NUMBER
    IS
    BEGIN
        IF n2 = 0 THEN
            RAISE_APPLICATION_ERROR(-20001, 'No se puede dividir entre cero');
        END IF;

        RETURN n1 / n2;
    END dividir;

END ARITMETICA;

CREATE OR REPLACE PACKAGE ARITMETICA AS

    PROCEDURE sumar(
        n1 NUMBER,
        n2 NUMBER
    );

    PROCEDURE restar(
        n1 NUMBER,
        n2 NUMBER
    );

    FUNCTION multiplicar(
        n1 NUMBER,
        n2 NUMBER
    ) RETURN NUMBER;

    FUNCTION dividir(
        n1 NUMBER,
        n2 NUMBER
    ) RETURN NUMBER;

END ARITMETICA;
